1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
3	const CURSE_SURCHARGE_RATE = 0.5;
4	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
5	const HIGH_ENCHANTMENT_THRESHOLD = 5;
6	const LOYALTY_DISCOUNT_RATE = 0.2;
7	const LOYALTY_YEARS_THRESHOLD = 2;
8	const FOLLOWUP_CONTRACT_DISCOUNT_RATE = 0.15;
9	const DEDUCTIBLE = 100;
10	const CAP_MULTIPLIER = 2;
11	const HIGH_ENCHANTMENT_PAYOUT_THRESHOLD = 8;
12	const HIGH_ENCHANTMENT_PAYOUT_RATE = 0.5;
13	
14	const INSURANCE_VALUE_BY_ITEM_TYPE: Record<string, number> = {
15	  sword: 1000,
16	  amulet: 600,
17	  staff: 800,
18	  potion: 400,
19	  rune: 250,
20	  moonstone: 250,
21	};
22	const COMPONENT_BASE_PRICE = 25;
23	const COMPONENT_BLOCK_SIZE = 3;
24	const COMPONENT_BLOCK_PRICE = 60;
25	
26	const BASE_PRICE_BY_ITEM_TYPE: Record<string, number> = {
27	  sword: 100,
28	  amulet: 60,
29	  staff: 80,
30	  potion: 40,
31	};
32	
33	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
34	
35	type Item = { type: string; cursed?: boolean; enchantment?: number; material?: string };
36	type Customer = { yearsWithMHPCO: number };
37	
38	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
39	
40	const mainItemBasePrice = (item: Item): number =>
41	  BASE_PRICE_BY_ITEM_TYPE[item.type] ?? 0;
42	
43	const componentGroupBasePrice = (count: number): number =>
44	  count === COMPONENT_BLOCK_SIZE
45	    ? COMPONENT_BLOCK_PRICE
46	    : count * COMPONENT_BASE_PRICE;
47	
48	const groupComponentsByType = (items: Item[]): Map<string, number> => {
49	  const groups = new Map<string, number>();
50	  for (const item of items) {
51	    if (!isComponent(item)) continue;
52	    groups.set(item.type, (groups.get(item.type) ?? 0) + 1);
53	  }
54	  return groups;
55	};
56	
57	const sum = (numbers: number[]): number =>
58	  numbers.reduce((total, n) => total + n, 0);
59	
60	const policyBasePremium = (items: Item[]): number => {
61	  const mainItemPremiums = items
62	    .filter((item) => !isComponent(item))
63	    .map(mainItemBasePrice);
64	  const componentGroupPremiums = [...groupComponentsByType(items).values()].map(
65	    componentGroupBasePrice,
66	  );
67	  return sum([...mainItemPremiums, ...componentGroupPremiums]);
68	};
69	
70	const curseSurcharge = (item: Item): number =>
71	  item.cursed ? mainItemBasePrice(item) * CURSE_SURCHARGE_RATE : 0;
72	
73	const highEnchantmentSurcharge = (item: Item): number =>
74	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD
75	    ? mainItemBasePrice(item) * HIGH_ENCHANTMENT_SURCHARGE_RATE
76	    : 0;
77	
78	const itemSurcharges = (items: Item[]): number =>
79	  sum(items.map((item) => curseSurcharge(item) + highEnchantmentSurcharge(item)));
80	
81	const loyaltyDiscount = (customer: Customer, basePremium: number): number =>
82	  customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD
83	    ? basePremium * LOYALTY_DISCOUNT_RATE
84	    : 0;
85	
86	type QuoteContext = { contractIndex?: number };
87	
88	const followUpDiscount = (
89	  context: QuoteContext,
90	  basePremium: number,
91	): number =>
92	  (context.contractIndex ?? 0) >= 1
93	    ? basePremium * FOLLOWUP_CONTRACT_DISCOUNT_RATE
94	    : 0;
95	
96	export const quote = (
97	  customer: Customer,
98	  items: Item[],
99	  context: QuoteContext = {},
100	): number => {
101	  const basePremium = policyBasePremium(items);
102	  const firstInsuranceSurcharge = basePremium * FIRST_INSURANCE_SURCHARGE_RATE;
103	  return Math.ceil(
104	    basePremium +
105	      firstInsuranceSurcharge -
106	      loyaltyDiscount(customer, basePremium) -
107	      followUpDiscount(context, basePremium) +
108	      itemSurcharges(items) +
109	      PROCESSING_FEE,
110	  );
111	};
112	
113	type Policy = { items: Item[] };
114	type Damage = { itemType: string; amount: number };
115	type Incident = { cause?: string; damages: Damage[] };
116	type ClaimResult = { payout: number; remainingCap: number };
117	
118	const policyInsuranceSum = (policy: Policy): number =>
119	  sum(policy.items.map((item) => INSURANCE_VALUE_BY_ITEM_TYPE[item.type] ?? 0));
120	
121	const policyCap = (policy: Policy): number =>
122	  policyInsuranceSum(policy) * CAP_MULTIPLIER;
123	
124	const findPolicyItem = (policy: Policy, itemType: string): Item | undefined =>
125	  policy.items.find((item) => item.type === itemType);
126	
127	const payoutRateForItem = (item: Item | undefined): number =>
128	  (item?.enchantment ?? 0) >= HIGH_ENCHANTMENT_PAYOUT_THRESHOLD
129	    ? HIGH_ENCHANTMENT_PAYOUT_RATE
130	    : 1;
131	
132	const payoutForDamage = (policy: Policy, damage: Damage): number => {
133	  const rate = payoutRateForItem(findPolicyItem(policy, damage.itemType));
134	  return Math.max(0, damage.amount * rate - DEDUCTIBLE);
135	};
136	
137	type QuoteStep = { op: "quote"; items: Item[] };
138	type ClaimStep = { op: "claim"; policy: number; incident: Incident };
139	type ScenarioStep = QuoteStep | ClaimStep;
140	type Scenario = { customer: Customer; steps: ScenarioStep[] };
141	type QuoteResult = { premium: number };
142	type ScenarioStepResult = QuoteResult | ClaimResult;
143	type ScenarioOutcome = { results: ScenarioStepResult[] };
144	
145	const runQuoteStep = (customer: Customer, step: QuoteStep): QuoteResult => ({
146	  premium: quote(customer, step.items),
147	});
148	
149	export const runScenario = (scenario: Scenario): ScenarioOutcome => {
150	  const paidByPolicy = new Map<number, number>();
151	  const results: ScenarioStepResult[] = scenario.steps.map((step) => {
152	    if (step.op === "quote") {
153	      return runQuoteStep(scenario.customer, step);
154	    }
155	    const policyStep = scenario.steps[step.policy] as QuoteStep;
156	    const policy: Policy = { items: policyStep.items };
157	    const alreadyPaid = paidByPolicy.get(step.policy) ?? 0;
158	    const result = claim(policy, step.incident, alreadyPaid);
159	    paidByPolicy.set(step.policy, alreadyPaid + result.payout);
160	    return result;
161	  });
162	  return { results };
163	};
164	
165	export const claim = (
166	  policy: Policy,
167	  incident: Incident,
168	  alreadyPaid: number = 0,
169	): ClaimResult => {
170	  const cap = policyCap(policy);
171	  const remainingBefore = cap - alreadyPaid;
172	  const desiredPayout = sum(
173	    incident.damages.map((damage) => payoutForDamage(policy, damage)),
174	  );
175	  const payout = Math.min(desiredPayout, remainingBefore);
176	  const remainingCap = remainingBefore - payout;
177	  return { payout: Math.floor(payout), remainingCap };
178	};
